// ============================================================
// ASSET LOADER
// ============================================================
class AssetLoader {
  constructor() {
    this.images = {};
    this.pokemonData = {};
    this.movesData = {};
    this.progress = 0;
    this.total = 0;
    this.loaded = 0;
    this.errors = [];
  }

  async loadAll() {
    this.total = 2 + 2 + 4 + 4; // 2 pokemon data + 2 sprites + 4+4 move data
    this.loaded = 0;

    // Fetch pokemon data
    const [bData, cData] = await Promise.all([
      this._fetchPokemon(1),
      this._fetchPokemon(4)
    ]);
    this.pokemonData[1] = bData;
    this.pokemonData[4] = cData;
    this.loaded += 2;
    this._updateProgress();

    // Fetch move data for both pokemon
    await Promise.all([
      this._fetchMoves(bData, 1),
      this._fetchMoves(cData, 4)
    ]);

    // Load sprites
    await Promise.all([
      this._loadImage('front_4', `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/4.png`),
      this._loadImage('back_1', `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/1.png`)
    ]);
    this.loaded += 2;
    this._updateProgress();

    return true;
  }

  async _fetchPokemon(id) {
    try {
      const resp = await fetch(`https://pokeapi.co/api/v2/pokemon/${id}`);
      if (!resp.ok) throw new Error('fetch failed');
      return await resp.json();
    } catch(e) {
      this.errors.push(`Pokemon ${id}: ${e.message}`);
      return this._fallbackPokemon(id);
    }
  }

  _fallbackPokemon(id) {
    if (id === 1) return {
      id:1, name:'bulbasaur',
      types:[{type:{name:'grass'}},{type:{name:'poison'}}],
      stats:[{stat:{name:'hp'},base_stat:45},{stat:{name:'attack'},base_stat:49},{stat:{name:'defense'},base_stat:49},{stat:{name:'special-attack'},base_stat:65},{stat:{name:'special-defense'},base_stat:65},{stat:{name:'speed'},base_stat:45}],
      moves:[{move:{name:'tackle',url:'https://pokeapi.co/api/v2/move/33/'}},{move:{name:'vine-whip',url:'https://pokeapi.co/api/v2/move/22/'}},{move:{name:'growl',url:'https://pokeapi.co/api/v2/move/45/'}},{move:{name:'leech-seed',url:'https://pokeapi.co/api/v2/move/73/'}}]
    };
    return {
      id:4, name:'charmander',
      types:[{type:{name:'fire'}}],
      stats:[{stat:{name:'hp'},base_stat:39},{stat:{name:'attack'},base_stat:52},{stat:{name:'defense'},base_stat:43},{stat:{name:'special-attack'},base_stat:60},{stat:{name:'special-defense'},base_stat:50},{stat:{name:'speed'},base_stat:65}],
      moves:[{move:{name:'scratch',url:'https://pokeapi.co/api/v2/move/10/'}},{move:{name:'ember',url:'https://pokeapi.co/api/v2/move/52/'}},{move:{name:'growl',url:'https://pokeapi.co/api/v2/move/45/'}},{move:{name:'smokescreen',url:'https://pokeapi.co/api/v2/move/108/'}}]
    };
  }

  async _fetchMoves(pokemonData, id) {
    const moveList = pokemonData.moves ? pokemonData.moves.slice(0, 4) : [];
    const movePromises = moveList.map(m => this._fetchMove(m.move.url, m.move.name));
    const moves = await Promise.all(movePromises);
    this.movesData[id] = moves.filter(Boolean);
    this.loaded += moveList.length;
    this._updateProgress();
  }

  async _fetchMove(url, name) {
    try {
      const resp = await fetch(url);
      if (!resp.ok) throw new Error('fetch failed');
      const data = await resp.json();
      return {
        name: data.name,
        power: data.power || 0,
        type: data.type ? data.type.name : 'normal',
        pp: data.pp || 10,
        maxPP: data.pp || 10,
        accuracy: data.accuracy || 100,
        damageClass: data.damage_class ? data.damage_class.name : 'physical'
      };
    } catch(e) {
      return this._fallbackMove(name);
    }
  }

  _fallbackMove(name) {
    const fallbacks = {
      'tackle':    {name:'tackle',    power:40, type:'normal', pp:35, maxPP:35, accuracy:100, damageClass:'physical'},
      'vine-whip': {name:'vine-whip', power:45, type:'grass',  pp:25, maxPP:25, accuracy:100, damageClass:'special'},
      'growl':     {name:'growl',     power:0,  type:'normal', pp:40, maxPP:40, accuracy:100, damageClass:'status'},
      'leech-seed':{name:'leech-seed',power:0,  type:'grass',  pp:10, maxPP:10, accuracy:90,  damageClass:'status'},
      'scratch':   {name:'scratch',   power:40, type:'normal', pp:35, maxPP:35, accuracy:100, damageClass:'physical'},
      'ember':     {name:'ember',     power:40, type:'fire',   pp:25, maxPP:25, accuracy:100, damageClass:'special'},
      'smokescreen':{name:'smokescreen',power:0,type:'normal', pp:20, maxPP:20, accuracy:100, damageClass:'status'}
    };
    return fallbacks[name] || {name: name||'tackle', power:40, type:'normal', pp:35, maxPP:35, accuracy:100, damageClass:'physical'};
  }

  _loadImage(key, url) {
    return new Promise((resolve) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => { this.images[key] = img; resolve(img); };
      img.onerror = () => { this.images[key] = null; resolve(null); };
      img.src = url;
    });
  }

  _updateProgress() {
    this.progress = this.total > 0 ? this.loaded / this.total : 0;
  }
}

// ============================================================
// DIALOG MANAGER
// ============================================================
class DialogManager {
  constructor() {
    this.active = false;
    this.lines = [];
    this.currentLine = 0;
    this.displayText = '';
    this.targetText = '';
    this.charIndex = 0;
    this.lastCharTime = 0;
    this.charDelay = 30;
    this.done = false;
    this.onComplete = null;
  }

  show(lines, onComplete) {
    this.active = true;
    this.lines = Array.isArray(lines) ? lines : [lines];
    this.currentLine = 0;
    this.done = false;
    this.onComplete = onComplete || null;
    this._startLine(0);
  }

  _startLine(idx) {
    this.targetText = this.lines[idx] || '';
    this.displayText = '';
    this.charIndex = 0;
    this.lastCharTime = performance.now();
    this.done = false;
  }

  update(now) {
    if (!this.active) return;
    if (this.charIndex < this.targetText.length) {
      const elapsed = now - this.lastCharTime;
      const charsToAdd = Math.floor(elapsed / this.charDelay);
      if (charsToAdd > 0) {
        this.charIndex = Math.min(this.charIndex + charsToAdd, this.targetText.length);
        this.displayText = this.targetText.slice(0, this.charIndex);
        this.lastCharTime = now;
      }
    } else {
      if (!this.done) this.done = true;
    }
  }

  advance() {
    if (!this.active) return false;
    if (this.charIndex < this.targetText.length) {
      // Skip to end of current line
      this.charIndex = this.targetText.length;
      this.displayText = this.targetText;
      this.done = true;
      return false;
    }
    if (this.done) {
      this.currentLine++;
      if (this.currentLine < this.lines.length) {
        this._startLine(this.currentLine);
        return false;
      } else {
        this.active = false;
        if (this.onComplete) this.onComplete();
        return true;
      }
    }
    return false;
  }

  draw(ctx) {
    if (!this.active) return;
    const bx = 0, by = CANVAS_H - 120, bw = CANVAS_W, bh = 120;
    // Box
    ctx.fillStyle = 'rgba(0,0,0,0.85)';
    ctx.fillRect(bx, by, bw, bh);
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.strokeRect(bx+4, by+4, bw-8, bh-8);
    // Text
    ctx.fillStyle = '#fff';
    ctx.font = '18px "Courier New", monospace';
    ctx.fillText(this.displayText, bx+20, by+40);
    // Prompt arrow
    if (this.done) {
      const t = (performance.now() / 400) % 1;
      const arrowY = by + bh - 20 + Math.sin(t * Math.PI * 2) * 3;
      ctx.fillText('▼', bw - 40, arrowY);
    }
  }
}

// ============================================================
// MAP ENGINE
// ============================================================
class MapEngine {
  constructor() {
    this.playerX = 10; this.playerY = 8;
    this.npcX = 10; this.npcY = 5;
    this.npcDir = 2; // facing down
    // Smooth movement
    this.moving = false;
    this.moveFrame = 0;
    this.moveFrames = 8;
    this.moveFromX = this.playerX; this.moveFromY = this.playerY;
    this.moveToX = this.playerX;   this.moveToY = this.playerY;
    this.walkFrame = 0; // for leg animation
    this.onEncounter = null;
    this.onNPCDialog = null;
    this.lastStepWasTall = false;
  }

  canMove(tx, ty) {
    if (tx < 0 || ty < 0 || tx >= MAP_W || ty >= MAP_H) return false;
    const t = MAP_DATA[ty][tx];
    if (t === TILE_WATER) return false;
    return true;
  }

  tryMove(dx, dy) {
    if (this.moving) return;
    const nx = this.playerX + dx;
    const ny = this.playerY + dy;
    if (!this.canMove(nx, ny)) return;
    // check NPC collision
    if (nx === this.npcX && ny === this.npcY) return;

    this.moveFromX = this.playerX;
    this.moveFromY = this.playerY;
    this.moveToX = nx;
    this.moveToY = ny;
    this.moving = true;
    this.moveFrame = 0;
  }

  update() {
    if (!this.moving) return;
    this.moveFrame++;
    if (this.moveFrame >= this.moveFrames) {
      this.playerX = this.moveToX;
      this.playerY = this.moveToY;
      this.moving = false;
      this.walkFrame++;
      // check tall grass encounter
      const tile = MAP_DATA[this.playerY][this.playerX];
      if (tile === TILE_TALL && Math.random() < 0.2) {
        if (this.onEncounter) this.onEncounter();
      }
    }
  }

  isNearNPC() {
    const dx = Math.abs(this.playerX - this.npcX);
    const dy = Math.abs(this.playerY - this.npcY);
    return (dx + dy) <= 1 && !(dx === 0 && dy === 0);
  }

  getPlayerDrawPos() {
    if (!this.moving) {
      return { x: this.playerX * TILE, y: this.playerY * TILE };
    }
    const t = this.moveFrame / this.moveFrames;
    return {
      x: (this.moveFromX + (this.moveToX - this.moveFromX) * t) * TILE,
      y: (this.moveFromY + (this.moveToY - this.moveFromY) * t) * TILE
    };
  }

  drawTiles(ctx) {
    for (let ry = 0; ry < MAP_H; ry++) {
      for (let rx = 0; rx < MAP_W; rx++) {
        const t = MAP_DATA[ry][rx];
        ctx.fillStyle = TILE_COLORS[t];
        ctx.fillRect(rx * TILE, ry * TILE, TILE, TILE);
        // Grid lines subtle
        if (t !== TILE_WATER) {
          ctx.strokeStyle = 'rgba(0,0,0,0.05)';
          ctx.lineWidth = 0.5;
          ctx.strokeRect(rx * TILE, ry * TILE, TILE, TILE);
        }
        // Tall grass detail
        if (t === TILE_TALL) {
          ctx.fillStyle = '#1a5533';
          ctx.fillRect(rx*TILE+4, ry*TILE+2, 3, 14);
          ctx.fillRect(rx*TILE+10, ry*TILE+5, 3, 10);
          ctx.fillRect(rx*TILE+18, ry*TILE+3, 3, 12);
          ctx.fillRect(rx*TILE+24, ry*TILE+7, 3, 8);
        }
        // Water shimmer
        if (t === TILE_WATER) {
          ctx.fillStyle = 'rgba(100,180,255,0.3)';
          const wt = (Math.sin(performance.now()/800 + rx + ry) + 1) * 0.5;
          ctx.fillRect(rx*TILE, ry*TILE + wt*4, TILE, 4);
        }
      }
    }
  }

  drawPlayer(ctx) {
    const pos = this.getPlayerDrawPos();
    const px = pos.x + 4, py = pos.y + 2;
    const bob = this.moving ? Math.sin(this.moveFrame / this.moveFrames * Math.PI) * 2 : 0;

    // Body
    ctx.fillStyle = '#e74c3c';
    ctx.fillRect(px+4, py+8-bob, 16, 14);
    // Head
    ctx.fillStyle = '#f4c78d';
    ctx.fillRect(px+5, py+2-bob, 14, 10);
    // Hat
    ctx.fillStyle = '#e74c3c';
    ctx.fillRect(px+4, py-bob, 16, 5);
    ctx.fillStyle = '#c0392b';
    ctx.fillRect(px+2, py+2-bob, 20, 2);
    // Eyes
    ctx.fillStyle = '#222';
    ctx.fillRect(px+7, py+5-bob, 2, 2);
    ctx.fillRect(px+13, py+5-bob, 2, 2);
    // Legs
    const legAnim = Math.sin(this.walkFrame * 0.8) * 2;
    ctx.fillStyle = '#2c3e50';
    ctx.fillRect(px+5, py+22-bob, 5, 6+legAnim);
    ctx.fillRect(px+12, py+22-bob, 5, 6-legAnim);
    // Shoes
    ctx.fillStyle = '#e74c3c';
    ctx.fillRect(px+4, py+28-bob+legAnim, 6, 3);
    ctx.fillRect(px+11, py+28-bob-legAnim, 6, 3);
  }

  drawNPC(ctx) {
    const nx = this.npcX * TILE + 4;
    const ny = this.npcY * TILE + 2;
    // Rival sprite - blue outfit
    ctx.fillStyle = '#3498db';
    ctx.fillRect(nx+4, ny+8, 16, 14);
    ctx.fillStyle = '#f4c78d';
    ctx.fillRect(nx+5, ny+2, 14, 10);
    ctx.fillStyle = '#2980b9';
    ctx.fillRect(nx+4, ny, 16, 5);
    ctx.fillStyle = '#1a6fa0';
    ctx.fillRect(nx+2, ny+2, 20, 2);
    ctx.fillStyle = '#222';
    ctx.fillRect(nx+7, ny+5, 2, 2);
    ctx.fillRect(nx+13, ny+5, 2, 2);
    ctx.fillStyle = '#1a252f';
    ctx.fillRect(nx+5, ny+22, 5, 6);
    ctx.fillRect(nx+12, ny+22, 5, 6);
    ctx.fillStyle = '#3498db';
    ctx.fillRect(nx+4, ny+28, 6, 3);
    ctx.fillRect(nx+11, ny+28, 6, 3);
    // "!" bubble if near player
    if (this.isNearNPC()) {
      ctx.fillStyle = '#fff';
      ctx.strokeStyle = '#000';
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.ellipse(nx+16, ny-8, 10, 7, 0, 0, Math.PI*2);
      ctx.fill();
      ctx.stroke();
      ctx.fillStyle = '#e74c3c';
      ctx.font = 'bold 12px "Courier New"';
      ctx.fillText('Z', nx+12, ny-4);
    }
  }

  draw(ctx) {
    this.drawTiles(ctx);
    this.drawNPC(ctx);
    this.drawPlayer(ctx);
  }
}

// ============================================================
// BATTLE ENGINE
// ============================================================
class BattleEngine {
  constructor(assets) {
    this.assets = assets;
    this.state = 'idle'; // idle, transition, playerTurn, enemyTurn, animating, result
    this.player = null;
    this.enemy = null;
    this.playerShake = 0;
    this.enemyShake = 0;
    this.playerHPTarget = 0;
    this.enemyHPTarget = 0;
    this.battleLog = [];
    this.logIndex = 0;
    this.showingLog = false;
    this.logText = '';
    this.logDisplayText = '';
    this.logCharIndex = 0;
    this.lastLogCharTime = 0;
    this.logDone = false;
    this.subState = '';
    this.moveSelectIdx = 0;
    this.menuState = 'main'; // main, fight
    this.transitionPhase = 0;
    this.transitionAlpha = 0;
    this.transitionTimer = 0;
    this.flashFrames = 0;
    this.pixelSize = 1;
    this.result = null; // 'win','lose'
    this.onBattleEnd = null;
    this.pendingAction = null;
    this.pendingEnemy = null;
    this.animQueue = [];
    this.inputLocked = false;
    // HP bar lerp
    this.playerHPDisplay = 0;
    this.enemyHPDisplay = 0;
  }

  calcStats(base, lv) {
    const iv = 15, ev = 0;
    const hp = Math.floor((base.hp * 2 + iv + Math.floor(ev/4)) * lv / 100) + lv + 10;
    const atk = Math.floor((base.atk * 2 + iv + Math.floor(ev/4)) * lv / 100) + 5;
    const def = Math.floor((base.def * 2 + iv + Math.floor(ev/4)) * lv / 100) + 5;
    const spa = Math.floor((base.spa * 2 + iv + Math.floor(ev/4)) * lv / 100) + 5;
    const spd = Math.floor((base.spd * 2 + iv + Math.floor(ev/4)) * lv / 100) + 5;
    const spe = Math.floor((base.spe * 2 + iv + Math.floor(ev/4)) * lv / 100) + 5;
    return { hp, atk, def, spa, spd, spe };
  }

  makePokemon(id, lv, isWild) {
    const data = this.assets.pokemonData[id];
    if (!data) return null;
    const statsRaw = {};
    for (const s of data.stats) {
      const n = s.stat.name;
      if (n === 'hp') statsRaw.hp = s.base_stat;
      else if (n === 'attack') statsRaw.atk = s.base_stat;
      else if (n === 'defense') statsRaw.def = s.base_stat;
      else if (n === 'special-attack') statsRaw.spa = s.base_stat;
      else if (n === 'special-defense') statsRaw.spd = s.base_stat;
      else if (n === 'speed') statsRaw.spe = s.base_stat;
    }
    const stats = this.calcStats(statsRaw, lv);
    const types = data.types.map(t => t.type.name);
    const moves = (this.assets.movesData[id] || []).slice(0, 4);
    // Ensure at least one move with power
    if (moves.length === 0) {
      moves.push({ name:'tackle', power:40, type:'normal', pp:35, maxPP:35, accuracy:100, damageClass:'physical' });
    }
    return {
      id, name: data.name, lv, types, moves,
      hp: stats.hp, maxHP: stats.hp,
      atk: stats.atk, def: stats.def,
      spa: stats.spa, spd: stats.spd, spe: stats.spe
    };
  }

  startBattle(onEnd) {
    this.onBattleEnd = onEnd;
    this.player = this.makePokemon(1, 5, false);
    this.enemy  = this.makePokemon(4, 5, true);
    this.playerHPDisplay = this.player.hp;
    this.enemyHPDisplay  = this.enemy.hp;
    this.playerHPTarget  = this.player.hp;
    this.enemyHPTarget   = this.enemy.hp;
    this.battleLog = [];
    this.logIndex = 0;
    this.menuState = 'main';
    this.moveSelectIdx = 0;
    this.result = null;
    this.inputLocked = false;
    this.animQueue = [];
    this.state = 'transition';
    this.transitionPhase = 0;
    this.transitionAlpha = 0;
    this.transitionTimer = 0;
    this.flashFrames = 20;
    this.pixelSize = 1;
    this._pushLog(`A wild ${this._cap(this.enemy.name)} appeared!`);
  }

  _cap(s) { return s ? s.charAt(0).toUpperCase() + s.slice(1) : ''; }

  _pushLog(msg) { this.battleLog.push(msg); }

  getTypeEff(moveType, defTypes) {
    let eff = 1;
    for (const dt of defTypes) {
      const row = TYPE_CHART[moveType];
      if (row && row[dt] !== undefined) eff *= row[dt];
    }
    return eff;
  }

  calcDamage(attacker, defender, move) {
    if (!move.power || move.power === 0) return 0;
    const lv = attacker.lv;
    const isSpecial = SPECIAL_TYPES.has(move.type);
    const A = isSpecial ? attacker.spa : attacker.atk;
    const D = isSpecial ? defender.spd : defender.def;
    const base = Math.floor(((Math.floor(2*lv/5+2) * move.power * A / D) / 50) + 2);
    const crit = Math.random() < 0.0625 ? 2 : 1;
    const stab = attacker.types.includes(move.type) ? 1.5 : 1;
    const eff = this.getTypeEff(move.type, defender.types);
    const rnd = Math.floor(Math.random() * 16) + 85;
    const dmg = Math.floor(Math.floor(Math.floor(base * crit) * stab) * eff * rnd / 100);
    return { dmg: Math.max(1, dmg), crit: crit === 2, eff };
  }

  enemyChooseMove() {
    const moves = this.enemy.moves.filter(m => m.power > 0 && m.pp > 0);
    if (moves.length === 0) {
      return this.enemy.moves.find(m => m.pp > 0) || this.enemy.moves[0];
    }
    // Check super effective
    const superEff = moves.filter(m => this.getTypeEff(m.type, this.player.types) >= 2);
    if (superEff.length > 0) return superEff.reduce((a,b) => a.power > b.power ? a : b);
    // Highest power
    return moves.reduce((a,b) => a.power > b.power ? a : b);
  }

  handlePlayerMove(moveIdx) {
    if (this.inputLocked) return;
    const move = this.player.moves[moveIdx];
    if (!move || move.pp <= 0) return;
    this.inputLocked = true;
    this.state = 'animating';
    move.pp--;

    const { dmg, crit, eff } = this.calcDamage(this.player, this.enemy, move);
    const enemyMove = this.enemyChooseMove();
    if (enemyMove) enemyMove.pp = Math.max(0, (enemyMove.pp||0) - 1);

    // Build animation queue
    this.animQueue = [];
    // Player attacks
    this.animQueue.push({ type: 'log', text: `${this._cap(this.player.name)} used ${this._cap(move.name.replace(/-/g,' '))}!` });
    if (crit) this.animQueue.push({ type: 'log', text: 'A critical hit!' });
    if (eff >= 2) this.animQueue.push({ type: 'log', text: "It's super effective!" });
    if (eff <= 0.5 && eff > 0) this.animQueue.push({ type: 'log', text: "It's not very effective..." });
    if (dmg > 0) {
      this.animQueue.push({ type: 'shake', target: 'enemy' });
      this.animQueue.push({ type: 'hp', target: 'enemy', amount: dmg });
    } else {
      this.animQueue.push({ type: 'log', text: "But it had no effect!" });
    }
    // Check enemy faint
    this.animQueue.push({ type: 'checkFaint', target: 'enemy' });

    // Enemy attacks (if alive)
    if (enemyMove && enemyMove.power > 0) {
      const { dmg: edm, crit: ec, eff: ee } = this.calcDamage(this.enemy, this.player, enemyMove);
      this.animQueue.push({ type: 'log', text: `Enemy ${this._cap(this.enemy.name)} used ${this._cap(enemyMove.name.replace(/-/g,' '))}!` });
      if (ec) this.animQueue.push({ type: 'log', text: 'A critical hit!' });
      if (ee >= 2) this.animQueue.push({ type: 'log', text: "It's super effective!" });
      if (ee <= 0.5 && ee > 0) this.animQueue.push({ type: 'log', text: "It's not very effective..." });
      this.animQueue.push({ type: 'shake', target: 'player' });
      this.animQueue.push({ type: 'hp', target: 'player', amount: edm });
    } else if (enemyMove) {
      this.animQueue.push({ type: 'log', text: `Enemy ${this._cap(this.enemy.name)} used ${this._cap(enemyMove.name.replace(/-/g,' '))}!` });
      this.animQueue.push({ type: 'log', text: `${this._cap(this.enemy.name)}'s stat changed!` });
    }
    this.animQueue.push({ type: 'checkFaint', target: 'player' });
    this.animQueue.push({ type: 'endTurn' });

    this._processAnimQueue();
  }

  handleRun() {
    if (this.inputLocked) return;
    this.inputLocked = true;
    this.animQueue = [
      { type: 'log', text: 'Got away safely!' },
      { type: 'endBattle', result: 'run' }
    ];
    this._processAnimQueue();
  }

  _processAnimQueue() {
    if (this.animQueue.length === 0) {
      this.state = 'playerTurn';
      this.inputLocked = false;
      return;
    }
    const action = this.animQueue.shift();

    if (action.type === 'log') {
      this._showLogText(action.text, () => this._processAnimQueue());
    } else if (action.type === 'shake') {
      if (action.target === 'enemy') this.enemyShake = 10;
      else this.playerShake = 10;
      setTimeout(() => this._processAnimQueue(), 300);
    } else if (action.type === 'hp') {
      if (action.target === 'enemy') {
        this.enemyHPTarget = Math.max(0, this.enemy.hp - action.amount);
        this.enemy.hp = this.enemyHPTarget;
      } else {
        this.playerHPTarget = Math.max(0, this.player.hp - action.amount);
        this.player.hp = this.playerHPTarget;
      }
      // Wait for HP lerp to finish
      setTimeout(() => this._processAnimQueue(), 600);
    } else if (action.type === 'checkFaint') {
      if (action.target === 'enemy' && this.enemy.hp <= 0) {
        this.animQueue = [
          { type: 'log', text: `${this._cap(this.enemy.name)} fainted!` },
          { type: 'endBattle', result: 'win' }
        ];
      } else if (action.target === 'player' && this.player.hp <= 0) {
        this.animQueue = [
          { type: 'log', text: `${this._cap(this.player.name)} fainted!` },
          { type: 'endBattle', result: 'lose' }
        ];
      }
      this._processAnimQueue();
    } else if (action.type === 'endTurn') {
      this.state = 'playerTurn';
      this.inputLocked = false;
      this.menuState = 'main';
    } else if (action.type === 'endBattle') {
      this.result = action.result;
      this.state = 'result';
      this.inputLocked = false;
    }
  }

  _showLogText(text, cb) {
    this.logText = text;
    this.logDisplayText = '';
    this.logCharIndex = 0;
    this.lastLogCharTime = performance.now();
    this.logDone = false;
    this.showingLog = true;
    this._logCallback = cb;
  }

  advanceLog() {
    if (!this.showingLog) return;
    if (this.logCharIndex < this.logText.length) {
      this.logCharIndex = this.logText.length;
      this.logDisplayText = this.logText;
      this.logDone = true;
    } else if (this.logDone) {
      this.showingLog = false;
      const cb = this._logCallback;
      this._logCallback = null;
      if (cb) cb();
    }
  }

  update(now) {
    // Shake
    if (this.playerShake > 0) this.playerShake--;
    if (this.enemyShake > 0) this.enemyShake--;

    // HP lerp
    const lerpSpeed = 2;
    if (Math.abs(this.playerHPDisplay - this.playerHPTarget) > 0.1) {
      this.playerHPDisplay += (this.playerHPTarget - this.playerHPDisplay) * 0.1;
    } else {
      this.playerHPDisplay = this.playerHPTarget;
    }
    if (Math.abs(this.enemyHPDisplay - this.enemyHPTarget) > 0.1) {
      this.enemyHPDisplay += (this.enemyHPTarget - this.enemyHPDisplay) * 0.1;
    } else {
      this.enemyHPDisplay = this.enemyHPTarget;
    }

    // Log typewriter
    if (this.showingLog && this.logCharIndex < this.logText.length) {
      const elapsed = now - this.lastLogCharTime;
      const charsToAdd = Math.floor(elapsed / 30);
      if (charsToAdd > 0) {
        this.logCharIndex = Math.min(this.logCharIndex + charsToAdd, this.logText.length);
        this.logDisplayText = this.logText.slice(0, this.logCharIndex);
        this.lastLogCharTime = now;
        if (this.logCharIndex >= this.logText.length) this.logDone = true;
      }
    }
  }

  drawBackground(ctx) {
    // Sky gradient
    const grad = ctx.createLinearGradient(0, 0, 0, CANVAS_H * 0.6);
    grad.addColorStop(0, '#87ceeb');
    grad.addColorStop(1, '#b0e0f7');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H - 160);

    // Ground
    ctx.fillStyle = '#8b4513';
    ctx.fillRect(0, CANVAS_H - 200, CANVAS_W, 40);
    ctx.fillStyle = '#6b3410';
    ctx.fillRect(0, CANVAS_H - 163, CANVAS_W, 3);

    // Enemy platform (elevated)
    ctx.fillStyle = '#7a5230';
    ctx.fillRect(340, CANVAS_H - 235, 200, 40);
    ctx.fillStyle = '#9b6a3c';
    ctx.fillRect(340, CANVAS_H - 240, 200, 8);

    // Player platform
    ctx.fillStyle = '#7a5230';
    ctx.fillRect(60, CANVAS_H - 200, 200, 35);
    ctx.fillStyle = '#9b6a3c';
    ctx.fillRect(60, CANVAS_H - 205, 200, 8);

    // Bottom panel background
    ctx.fillStyle = '#111';
    ctx.fillRect(0, CANVAS_H - 160, CANVAS_W, 160);
    ctx.strokeStyle = '#555';
    ctx.lineWidth = 2;
    ctx.strokeRect(0, CANVAS_H - 160, CANVAS_W, 160);
  }

  drawHPBar(ctx, x, y, w, current, max, label, lv, isPlayer, showNumbers) {
    // Gen 3 style panel
    ctx.fillStyle = '#f0f0f0';
    ctx.fillRect(x, y, w, 48);
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 2;
    ctx.strokeRect(x, y, w, 48);

    // Name + Level
    ctx.fillStyle = '#111';
    ctx.font = 'bold 14px "Courier New", monospace';
    ctx.fillText(label, x+8, y+18);
    ctx.font = '12px "Courier New", monospace';
    ctx.fillText(`Lv${lv}`, x+w-45, y+18);

    // HP label
    ctx.fillStyle = '#333';
    ctx.font = 'bold 11px "Courier New", monospace';
    ctx.fillText('HP:', x+8, y+36);

    // Bar background
    const barX = x+32, barY = y+27, barW = w-50, barH = 8;
    ctx.fillStyle = '#555';
    ctx.fillRect(barX, barY, barW, barH);

    // HP bar color
    const ratio = Math.max(0, current) / max;
    const dispRatio = Math.max(0, this[isPlayer ? 'playerHPDisplay' : 'enemyHPDisplay']) / max;
    let color = '#0f0';
    if (ratio < 0.5) color = '#ff0';
    if (ratio < 0.2) color = '#f00';
    ctx.fillStyle = color;
    ctx.fillRect(barX, barY, Math.round(dispRatio * barW), barH);

    // Numbers for player
    if (showNumbers) {
      ctx.fillStyle = '#111';
      ctx.font = '11px "Courier New", monospace';
      ctx.fillText(`${Math.ceil(Math.max(0, this.playerHPDisplay))}/${max}`, barX, y+46);
    }
  }

  drawSprites(ctx) {
    // Enemy front sprite (Charmander) - top right
    const ex = 380, ey = CANVAS_H - 310;
    if (this.assets.images['front_4']) {
      const shakeX = this.enemyShake > 0 ? Math.sin(this.enemyShake * 2) * 4 : 0;
      ctx.drawImage(this.assets.images['front_4'], ex + shakeX, ey, 96, 96);
    } else {
      ctx.fillStyle = '#e74c3c';
      ctx.fillRect(ex, ey, 96, 96);
      ctx.fillStyle = '#c0392b';
      ctx.fillText('Charmander', ex, ey+50);
    }

    // Player back sprite (Bulbasaur) - bottom left
    const px2 = 80, py2 = CANVAS_H - 300;
    if (this.assets.images['back_1']) {
      const shakeX = this.playerShake > 0 ? Math.sin(this.playerShake * 2) * 4 : 0;
      ctx.drawImage(this.assets.images['back_1'], px2 + shakeX, py2, 96, 96);
    } else {
      ctx.fillStyle = '#2ecc71';
      ctx.fillRect(px2, py2, 96, 96);
    }
  }

  drawPanels(ctx) {
    // Enemy HP panel (top left)
    this.drawHPBar(ctx, 10, 10, 220, this.enemy.hp, this.enemy.maxHP,
      this._cap(this.enemy.name), this.enemy.lv, false, false);

    // Player HP panel (bottom right area, above menu)
    this.drawHPBar(ctx, CANVAS_W - 230, CANVAS_H - 215, 220, this.player.hp, this.player.maxHP,
      this._cap(this.player.name), this.player.lv, true, true);
  }

  drawMenu(ctx) {
    const mx = 0, my = CANVAS_H - 160, mw = CANVAS_W, mh = 160;

    if (this.showingLog || this.state === 'animating') {
      // Show battle log
      ctx.fillStyle = '#fff';
      ctx.font = '16px "Courier New", monospace';
      ctx.fillText(this.logDisplayText, mx + 16, my + 40);
      return;
    }

    if (this.menuState === 'main') {
      // 2x2 grid
      const buttons = ['FIGHT', 'BAG', 'POKEMON', 'RUN'];
      ctx.fillStyle = '#fff';
      ctx.font = 'bold 18px "Courier New", monospace';
      buttons.forEach((b, i) => {
        const bx = mx + (i % 2) * (mw/2) + 20;
        const by = my + Math.floor(i/2) * 70 + 45;
        ctx.fillText(b, bx, by);
      });
      // Prompt
      ctx.font = '14px "Courier New", monospace';
      ctx.fillStyle = '#aaa';
      ctx.fillText('What will you do?', mx+16, my+22);
    } else if (this.menuState === 'fight') {
      const moves = this.player.moves;
      ctx.fillStyle = '#aaa';
      ctx.font = '14px "Courier New", monospace';
      ctx.fillText('Choose a move:', mx+16, my+22);
      moves.forEach((m, i) => {
        const bx = mx + (i % 2) * (mw/2) + 20;
        const by = my + Math.floor(i/2) * 55 + 50;
        const selected = this.moveSelectIdx === i;
        if (selected) {
          ctx.fillStyle = '#ff0';
          ctx.fillRect(bx - 12, by - 18, mw/2 - 20, 26);
          ctx.fillStyle = '#000';
        } else {
          ctx.fillStyle = '#fff';
        }
        const moveName = this._cap(m.name.replace(/-/g,' '));
        ctx.font = 'bold 15px "Courier New", monospace';
        ctx.fillText(moveName, bx, by);
        ctx.font = '12px "Courier New", monospace';
        ctx.fillStyle = selected ? '#000' : '#aaa';
        ctx.fillText(`PP ${m.pp}/${m.maxPP} [${m.type.toUpperCase()}]`, bx, by+16);
      });
      ctx.fillStyle = '#aaa';
      ctx.font = '13px "Courier New", monospace';
      ctx.fillText('[Arrow keys to navigate, Z/Enter to select, X/Esc to back]', mx+10, my+150);
    }
  }

  drawTransition(ctx) {
    if (this.state !== 'transition') return;
    const now = performance.now();
    if (!this.transitionStart) this.transitionStart = now;
    const elapsed = now - this.transitionStart;

    if (elapsed < 400) {
      // White flash in
      const alpha = Math.min(1, elapsed / 200);
      ctx.fillStyle = `rgba(255,255,255,${alpha})`;
      ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);
    } else if (elapsed < 800) {
      // Hold white
      ctx.fillStyle = '#fff';
      ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);
    } else if (elapsed < 1200) {
      // Mosaic pixelate effect
      const t = (elapsed - 800) / 400;
      const ps = Math.max(1, Math.floor((1 - t) * 20));
      ctx.fillStyle = '#fff';
      ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);
      // Draw pixelated grid overlay
      ctx.globalAlpha = t;
      for (let gy = 0; gy < CANVAS_H; gy += ps*2) {
        for (let gx = 0; gx < CANVAS_W; gx += ps*2) {
          const colors = ['#87ceeb','#8b4513','#226644','#000'];
          ctx.fillStyle = colors[Math.floor(Math.random()*colors.length)];
          ctx.fillRect(gx, gy, ps*2, ps*2);
        }
      }
      ctx.globalAlpha = 1;
    } else {
      // Battle begins
      this.state = 'playerTurn';
      this.menuState = 'main';
      this.transitionStart = null;
    }
  }

  drawResult(ctx) {
    ctx.fillStyle = 'rgba(0,0,0,0.7)';
    ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);
    ctx.font = 'bold 36px "Courier New", monospace';
    ctx.textAlign = 'center';
    if (this.result === 'win') {
      ctx.fillStyle = '#ffd700';
      ctx.fillText('Victory!', CANVAS_W/2, CANVAS_H/2 - 20);
    } else if (this.result === 'lose') {
      ctx.fillStyle = '#e74c3c';
      ctx.fillText('Defeated...', CANVAS_W/2, CANVAS_H/2 - 20);
    } else {
      ctx.fillStyle = '#fff';
      ctx.fillText('Got Away!', CANVAS_W/2, CANVAS_H/2 - 20);
    }
    ctx.font = '18px "Courier New", monospace';
    ctx.fillStyle = '#fff';
    ctx.fillText('Press R to return to map', CANVAS_W/2, CANVAS_H/2 + 30);
    ctx.textAlign = 'left';
  }

  draw(ctx, now) {
    if (this.state === 'transition') {
      // Draw map underneath (handled by game loop)
      this.drawTransition(ctx);
      return;
    }
    this.drawBackground(ctx);
    this.drawSprites(ctx);
    this.drawPanels(ctx);
    this.drawMenu(ctx);
    if (this.state === 'result') {
      this.drawResult(ctx);
    }
  }

  handleInput(key) {
    if (this.state === 'transition') return;

    if (this.showingLog) {
      if (key === 'z' || key === 'enter' || key === ' ') {
        this.advanceLog();
      }
      return;
    }

    if (this.state === 'result') {
      if (key === 'r') {
        if (this.onBattleEnd) this.onBattleEnd(this.result);
      }
      return;
    }

    if (this.state !== 'playerTurn') return;
    if (this.inputLocked) return;

    if (this.menuState === 'main') {
      if (key === 'z' || key === 'enter') {
        this.menuState = 'fight';
        this.moveSelectIdx = 0;
      } else if (key === 'arrowdown' || key === 's') {
        // BAG - just show msg
        this._showBagMsg();
      } else if (key === 'r' || (key === 'arrowright' && false)) {
        this.handleRun();
      }
    } else if (this.menuState === 'fight') {
      const moves = this.player.moves;
      if (key === 'arrowleft' || key === 'a') {
        this.moveSelectIdx = Math.max(0, this.moveSelectIdx - 1);
        if (this.moveSelectIdx % 2 === 1) this.moveSelectIdx--;
        // Actually just decrement
        this.moveSelectIdx = (this.moveSelectIdx - 1 + moves.length) % moves.length;
      } else if (key === 'arrowright' || key === 'd') {
        this.moveSelectIdx = (this.moveSelectIdx + 1) % moves.length;
      } else if (key === 'arrowup' || key === 'w') {
        if (this.moveSelectIdx >= 2) this.moveSelectIdx -= 2;
      } else if (key === 'arrowdown' || key === 's') {
        if (this.moveSelectIdx + 2 < moves.length) this.moveSelectIdx += 2;
      } else if (key === 'z' || key === 'enter') {
        this.handlePlayerMove(this.moveSelectIdx);
      } else if (key === 'x' || key === 'escape') {
        this.menuState = 'main';
      }
    }
  }

  _showBagMsg() {
    this.inputLocked = true;
    this.animQueue = [
      { type: 'log', text: "You have no items!" },
      { type: 'endTurn' }
    ];
    this._processAnimQueue();
  }
}

// ============================================================
// GAME LOOP (State Machine)
// ============================================================
class GameLoop {
  constructor() {
    this.canvas = document.getElementById('game');
    this.ctx = this.canvas.getContext('2d');
    this.state = 'loading'; // loading, title, map, battle, dialog
    this.assets = new AssetLoader();
    this.map = new MapEngine();
    this.dialog = new DialogManager();
    this.battle = null;
    this.keys = {};
    this.keyJustPressed = {};
    this.loadProgress = 0;
    this.loadText = 'Loading...';
    this.loadDots = 0;
    this.lastDotTime = 0;
    this.titleReady = false;
    this._lastFrameTime = 0;
    this._raf = null;
    this._setupInput();
    this._load();
  }

  _setupInput() {
    const consume = (key) => {
      const k = key.toLowerCase();
      // Map special keys
      const mapped = {
        'arrowup':'arrowup','arrowdown':'arrowdown','arrowleft':'arrowleft','arrowright':'arrowright',
        ' ':'z','enter':'enter','z':'z','x':'x','r':'r','escape':'escape',
        'a':'a','s':'s','d':'d','w':'w'
      };
      return mapped[k] || k;
    };

    window.addEventListener('keydown', (e) => {
      const k = consume(e.key);
      if (!this.keys[k]) {
        this.keyJustPressed[k] = true;
      }
      this.keys[k] = true;
      // Prevent scroll for arrow/space
      if (['arrowup','arrowdown','arrowleft','arrowright',' '].includes(e.key.toLowerCase())) {
        e.preventDefault();
      }
      this._handleKey(k);
    });

    window.addEventListener('keyup', (e) => {
      const k = consume(e.key);
      this.keys[k] = false;
    });
  }

  _handleKey(key) {
    if (this.state === 'loading') return;

    if (this.state === 'title') {
      if (key === 'enter' || key === 'z') {
        this.state = 'map';
      }
      return;
    }

    if (this.state === 'map') {
      if (this.dialog.active) {
        if (key === 'z' || key === 'enter') {
          this.dialog.advance();
        }
        return;
      }
      // Movement
      if (key === 'arrowup' || key === 'w') this.map.tryMove(0, -1);
      if (key === 'arrowdown' || key === 's') this.map.tryMove(0, 1);
      if (key === 'arrowleft' || key === 'a') this.map.tryMove(-1, 0);
      if (key === 'arrowright' || key === 'd') this.map.tryMove(1, 0);
      // NPC interaction
