      'smokescreen':{name:'smokescreen',power:0,type:'normal', pp:20, maxPP:20, accuracy:100, damageClass:'status'}
    };
    return fallbacks[name] || {name: name||'tackle', power:40, type:'normal', pp:35, maxPP:35, accuracy:100, damageClass:'physical'};
  }

  _loadImage(key, url) {
    return new Promise((resolve) => {
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => { this.images[key] = img; resolve(img); };
      img.onerror = () => { this.images[key] = null; resolve(null); };
      img.src = url;
    });
  }

  _updateProgress() {
    this.progress = this.total > 0 ? this.loaded / this.total : 0;
  }
}

