  }

  show(lines, onComplete) {
    this.active = true;
    this.lines = Array.isArray(lines) ? lines : [lines];
    this.currentLine = 0;
    this.done = false;
    this.onComplete = onComplete || null;
    this._startLine(0);
  }

  _startLine(idx) {
    this.targetText = this.lines[idx] || '';
    this.displayText = '';
    this.charIndex = 0;
    this.lastCharTime = performance.now();
    this.done = false;
  }

  update(now) {
    if (!this.active) return;
    if (this.charIndex < this.targetText.length) {
      const elapsed = now - this.lastCharTime;
      const charsToAdd = Math.floor(elapsed / this.charDelay);
      if (charsToAdd > 0) {
        this.charIndex = Math.min(this.charIndex + charsToAdd, this.targetText.length);
        this.displayText = this.targetText.slice(0, this.charIndex);
        this.lastCharTime = now;
      }
    } else {
      if (!this.done) this.done = true;
    }
  }

  advance() {
    if (!this.active) return false;
    if (this.charIndex < this.targetText.length) {
      // Skip to end of current line
      this.charIndex = this.targetText.length;
      this.displayText = this.targetText;
      this.done = true;
      return false;
    }
    if (this.done) {
      this.currentLine++;
      if (this.currentLine < this.lines.length) {
        this._startLine(this.currentLine);
        return false;
      } else {
        this.active = false;
        if (this.onComplete) this.onComplete();
        return true;
      }
    }
    return false;
  }

  draw(ctx) {
    if (!this.active) return;
    const bx = 0, by = CANVAS_H - 120, bw = CANVAS_W, bh = 120;
    // Box
    ctx.fillStyle = 'rgba(0,0,0,0.85)';
    ctx.fillRect(bx, by, bw, bh);
    ctx.strokeStyle = '#fff';
    ctx.lineWidth = 3;
    ctx.strokeRect(bx+4, by+4, bw-8, bh-8);
    // Text
    ctx.fillStyle = '#fff';
    ctx.font = '18px "Courier New", monospace';
    ctx.fillText(this.displayText, bx+20, by+40);
    // Prompt arrow
    if (this.done) {
      const t = (performance.now() / 400) % 1;
      const arrowY = by + bh - 20 + Math.sin(t * Math.PI * 2) * 3;
      ctx.fillText('▼', bw - 40, arrowY);
    }
  }
}

